"use client";

import React, { useEffect, useMemo, useRef } from "react";

type Message = {
  role: "user" | "assistant";
  content: string;
};

export default function BuilderSidebar(props: {
  isThinking: boolean;
  messages: Message[];
  promptDraft: string;
  onPromptDraftChange: (v: string) => void;
  onRunBuild: () => void;
}) {
  const { isThinking, messages, promptDraft, onPromptDraftChange, onRunBuild } = props;

  const listRef = useRef<HTMLDivElement | null>(null);

  const canRun = useMemo(() => promptDraft.trim().length > 0 && !isThinking, [promptDraft, isThinking]);

  useEffect(() => {
    const el = listRef.current;
    if (!el) return;
    el.scrollTop = el.scrollHeight;
  }, [messages, isThinking]);

  return (
    <div className="cb-sidebar-pad">
      <div className="cb-sidebar-card">
        {/* Header */}
        <div className="cb-sidebar-head">
          <div className="cb-sidebar-head__left">
            <div className="cb-sidebar-title">Chat</div>
            <div className="cb-sidebar-sub">Describe what you want. We turn it into a build plan.</div>
          </div>
          <div className="cb-sidebar-status">{isThinking ? "Thinking…" : "Ready"}</div>
        </div>

        {/* Messages */}
        <div ref={listRef} className="cb-sidebar-body">
          {messages.length === 0 ? (
            <div className="cb-sidebar-empty">
              <div className="cb-empty-card">
                <div className="cb-empty-title">CodeBot™ Builder</div>
                <div className="cb-empty-sub">Start with a clear request. Example:</div>
                <div className="cb-empty-example">
                  Build a landing page for a mobile detailing business. Add booking, pricing, and a clean homepage.
                </div>
              </div>
            </div>
          ) : (
            <div className="cb-msg-list">
              {messages.map((msg, i) => {
                const isUser = msg.role === "user";
                return (
                  <div key={i} className={isUser ? "cb-msg-row cb-msg-row--user" : "cb-msg-row cb-msg-row--ai"}>
                    <div className={isUser ? "cb-msg cb-msg--user" : "cb-msg cb-msg--ai"}>
                      {msg.content}
                    </div>
                  </div>
                );
              })}

              {isThinking ? (
                <div className="cb-msg-row cb-msg-row--ai">
                  <div className="cb-msg cb-msg--ai">Working…</div>
                </div>
              ) : null}
            </div>
          )}
        </div>

        {/* Composer */}
        <div className="cb-composer">
          <div className="cb-composer-row">
            <textarea
              className="cb-composer-input"
              value={promptDraft}
              rows={3}
              placeholder="Describe what you want to build…"
              onChange={(e) => onPromptDraftChange(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  // Enter ALWAYS builds. No Shift+Enter newline.
                  e.preventDefault();
                  if (canRun) onRunBuild();
                }
              }}
            />

            <button
              type="button"
              className={canRun ? "cb-composer-btn" : "cb-composer-btn cb-composer-btn--disabled"}
              disabled={!canRun}
              onClick={onRunBuild}
              title={canRun ? "Run build" : isThinking ? "Busy" : "Type a prompt"}
            >
              {isThinking ? "Thinking…" : "Build now"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
