"use client";

import React, { useEffect, useMemo, useRef, useState } from "react";
import AuthGate from "@/components/AuthGate";
import BuilderTopBar from "@/components/builder/BuilderTopBar";
import BuilderSidebar from "@/components/builder/BuilderSidebar";

type DeviceMode = "desktop" | "tablet" | "mobile";
type ViewMode = "preview" | "code";

type ChatRole = "user" | "assistant";
type ChatMessage = {
  role: ChatRole;
  content: string;
};

function safeId(): string {
  try {
    const c: any = globalThis.crypto;
    if (c?.randomUUID) return c.randomUUID();
  } catch {
    // ignore
  }
  return `proj_${Date.now()}_${Math.random().toString(16).slice(2)}`;
}

const API_BASE = process.env.NEXT_PUBLIC_CODEBOT_API_BASE || "/codebot/api";

type RunBuildPayload = {
  projectId: string;
  projectName: string;
  device: DeviceMode;
  view: ViewMode;
  prompt: string;
  messages: ChatMessage[];
};

type RunBuildJsonResponse = {
  ok?: boolean;
  assistant?: string;
  previewUrl?: string;
  files?: Array<{ path: string; content: string }>;
  error?: string;
};

const LEFT_W_KEY = "cb_builder_left_w_v2";
const STATE_KEY = "cb_builder_state_v2";

const MIN_LEFT = 320;
const MAX_LEFT = 560;

function clamp(n: number, min: number, max: number) {
  return Math.max(min, Math.min(max, n));
}

function readSearchParams() {
  try {
    const url = new URL(window.location.href);
    const project = url.searchParams.get("project") || "";
    const name = url.searchParams.get("name") || "";
    return { project, name };
  } catch {
    return { project: "", name: "" };
  }
}

function stripBuilderSearchParamsFromUrl() {
  try {
    const url = new URL(window.location.href);
    const had = url.searchParams.has("project") || url.searchParams.has("name");
    if (!had) return;

    url.searchParams.delete("project");
    url.searchParams.delete("name");
    window.history.replaceState({}, "", url.toString());
  } catch {
    // ignore
  }
}

function tryParseJson<T>(s: string): T | null {
  try {
    return JSON.parse(s) as T;
  } catch {
    return null;
  }
}

function sanitizeMessages(arr: any): ChatMessage[] {
  if (!Array.isArray(arr)) return [];
  const out: ChatMessage[] = [];
  for (const m of arr) {
    if (!m || typeof m !== "object") continue;
    const role = m.role === "assistant" ? "assistant" : m.role === "user" ? "user" : null;
    const content = typeof m.content === "string" ? m.content : null;
    if (!role || content === null) continue;
    out.push({ role, content });
  }
  return out.slice(-200);
}

export default function BuilderPage() {
  const [device, setDevice] = useState<DeviceMode>("desktop");
  const [view, setView] = useState<ViewMode>("preview");

  const [promptDraft, setPromptDraft] = useState<string>("");
  const [messages, setMessages] = useState<ChatMessage[]>([]);

  const [isThinking, setIsThinking] = useState(false);
  const [projectId, setProjectId] = useState<string>(() => safeId());
  const [activeProjectName, setActiveProjectName] = useState<string>("Untitled Project");

  const [previewUrl, setPreviewUrl] = useState<string>("");
  const [generatedFiles, setGeneratedFiles] = useState<Array<{ path: string; content: string }>>([]);
  const [lastError, setLastError] = useState<string>("");

  const abortRef = useRef<AbortController | null>(null);

  const [leftW, setLeftW] = useState<number>(() => {
    try {
      const raw = localStorage.getItem(LEFT_W_KEY);
      const n = raw ? Number(raw) : 380;
      return clamp(Number.isFinite(n) ? n : 380, MIN_LEFT, MAX_LEFT);
    } catch {
      return 380;
    }
  });

  const draggingRef = useRef(false);
  const dragStartXRef = useRef(0);
  const dragStartWRef = useRef(380);

  // Restore persisted state once
  useEffect(() => {
    try {
      const raw = localStorage.getItem(STATE_KEY);
      if (raw) {
        const s = tryParseJson<any>(raw);
        if (s && typeof s === "object") {
          if (typeof s.projectId === "string" && s.projectId) setProjectId(s.projectId);
          if (typeof s.projectName === "string" && s.projectName) setActiveProjectName(s.projectName);

          if (s.device === "desktop" || s.device === "tablet" || s.device === "mobile") setDevice(s.device);
          if (s.view === "preview" || s.view === "code") setView(s.view);

          if (typeof s.promptDraft === "string") setPromptDraft(s.promptDraft);

          const cleaned = sanitizeMessages(s.messages);
          if (cleaned.length) setMessages(cleaned);

          if (typeof s.previewUrl === "string") setPreviewUrl(s.previewUrl);

          if (Array.isArray(s.generatedFiles)) {
            const gf = s.generatedFiles
              .filter((f: any) => f && typeof f.path === "string" && typeof f.content === "string")
              .slice(0, 200);
            setGeneratedFiles(gf);
          }
        }
      }
    } catch {
      // ignore
    }

    // Override from share-link params (highest priority)
    const { project, name } = readSearchParams();
    if (project) setProjectId(project);
    if (name) setActiveProjectName(name);

    // Clean URL after consuming share params
    if (project || name) stripBuilderSearchParamsFromUrl();
  }, []);

  // Persist width + state
  useEffect(() => {
    try {
      localStorage.setItem(LEFT_W_KEY, String(leftW));
    } catch {
      // ignore
    }
  }, [leftW]);

  useEffect(() => {
    try {
      const snapshot = {
        projectId,
        projectName: activeProjectName,
        device,
        view,
        promptDraft,
        messages: messages.slice(-200),
        previewUrl,
        generatedFiles: generatedFiles.slice(0, 200),
      };
      localStorage.setItem(STATE_KEY, JSON.stringify(snapshot));
    } catch {
      // ignore
    }
  }, [projectId, activeProjectName, device, view, promptDraft, messages, previewUrl, generatedFiles]);

  // Resizer listeners
  useEffect(() => {
    function onMove(e: MouseEvent) {
      if (!draggingRef.current) return;
      const dx = e.clientX - dragStartXRef.current;
      const next = clamp(dragStartWRef.current + dx, MIN_LEFT, MAX_LEFT);
      setLeftW(next);
    }

    function onUp() {
      if (!draggingRef.current) return;
      draggingRef.current = false;
      document.body.style.cursor = "";
      document.body.style.userSelect = "";
    }

    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
    };
  }, []);

  function startDrag(e: React.MouseEvent) {
    draggingRef.current = true;
    dragStartXRef.current = e.clientX;
    dragStartWRef.current = leftW;
    document.body.style.cursor = "col-resize";
    document.body.style.userSelect = "none";
  }

  function resizeBy(delta: number) {
    setLeftW((w) => clamp(w + delta, MIN_LEFT, MAX_LEFT));
  }

  function newProjectLocal() {
    try {
      abortRef.current?.abort();
    } catch {
      // ignore
    }
    abortRef.current = null;

    setProjectId(safeId());
    setActiveProjectName("Untitled Project");
    setPromptDraft("");
    setMessages([]);
    setIsThinking(false);
    setView("preview");
    setDevice("desktop");
    setPreviewUrl("");
    setGeneratedFiles([]);
    setLastError("");
  }

  async function shareProject() {
    const url = new URL(window.location.href);
    url.pathname = url.pathname.replace(/\/+$/, "");
    if (!url.pathname.endsWith("/builder")) {
      url.pathname = url.pathname.replace(/\/builder.*$/, "/builder");
    }
    url.searchParams.set("project", projectId);
    url.searchParams.set("name", activeProjectName);
    const shareUrl = url.toString();

    try {
      await navigator.clipboard.writeText(shareUrl);
    } catch {
      window.prompt("Copy this link:", shareUrl);
    }
  }

  function exportProject() {
    const payload = {
      version: 3,
      exported_at: new Date().toISOString(),
      project: { id: projectId, name: activeProjectName },
      ui_state: { view, device, leftW },
      previewUrl,
      generatedFiles,
      messages,
    };

    const blob = new Blob([JSON.stringify(payload, null, 2)], {
      type: "application/json",
    });

    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);

    const safeName =
      activeProjectName
        .trim()
        .toLowerCase()
        .replace(/[^a-z0-9\-_]+/g, "-")
        .replace(/-+/g, "-")
        .replace(/(^-|-$)/g, "") || "project";

    a.download = `${safeName}.json`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    window.setTimeout(() => URL.revokeObjectURL(a.href), 2500);
  }

  function upsertAssistantProgress(nextText: string) {
    setMessages((prev) => {
      const last = prev[prev.length - 1];
      if (last && last.role === "assistant") {
        const copy = prev.slice();
        copy[copy.length - 1] = { role: "assistant", content: nextText };
        return copy;
      }
      return [...prev, { role: "assistant", content: nextText }];
    });
  }

  function cancelRun() {
    if (!isThinking) return;
    try {
      abortRef.current?.abort();
    } catch {
      // ignore
    }
    abortRef.current = null;
    setIsThinking(false);
    setLastError("Cancelled.");
    upsertAssistantProgress("Cancelled.");
  }

  async function runBuild() {
    const msg = promptDraft.trim();
    if (!msg || isThinking) return;

    setLastError("");
    setPromptDraft("");

    const userMsg: ChatMessage = { role: "user" as const, content: msg };
    const nextMsgs: ChatMessage[] = [...messages, userMsg].slice(-200);

    setMessages(nextMsgs);
    setIsThinking(true);

    // Create assistant slot immediately
    upsertAssistantProgress("Running…");

    const ac = new AbortController();
    abortRef.current = ac;

    const payload: RunBuildPayload = {
      projectId,
      projectName: activeProjectName,
      device,
      view,
      prompt: msg,
      messages: nextMsgs,
    };

    const endpoint = `${API_BASE.replace(/\/+$/, "")}/builder/run`;

    try {
      const res = await fetch(endpoint, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(payload),
        signal: ac.signal,
      });

      if (!res.ok) {
        const text = await res.text().catch(() => "");
        const detail = text?.trim() ? ` ${text.trim()}` : "";
        const err = `Build request failed (${res.status}).${detail}`;
        setLastError(err);
        upsertAssistantProgress(err);
        setIsThinking(false);
        abortRef.current = null;
        return;
      }

      const ct = res.headers.get("content-type") || "";

      // Streaming text
      if (ct.includes("text/plain") || ct.includes("text/event-stream")) {
        const reader = res.body?.getReader();
        if (!reader) {
          const err = "Backend returned streaming response but no body reader was available.";
          setLastError(err);
          upsertAssistantProgress(err);
          setIsThinking(false);
          abortRef.current = null;
          return;
        }

        const decoder = new TextDecoder();
        let acc = "";

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          acc += decoder.decode(value, { stream: true });

          const normalized = acc
            .split("\n")
            .map((line) => (line.startsWith("data:") ? line.slice(5).trimStart() : line))
            .join("\n")
            .trim();

          upsertAssistantProgress(normalized || "Running…");
        }

        setIsThinking(false);
        abortRef.current = null;
        return;
      }

      // JSON response
      if (ct.includes("application/json")) {
        const data = (await res.json().catch(() => null)) as RunBuildJsonResponse | null;

        if (!data) {
          const err = "Backend returned JSON but parsing failed.";
          setLastError(err);
          upsertAssistantProgress(err);
          setIsThinking(false);
          abortRef.current = null;
          return;
        }

        if (data.error) {
          setLastError(data.error);
          upsertAssistantProgress(data.error);
        } else {
          if (typeof data.assistant === "string" && data.assistant.trim()) {
            upsertAssistantProgress(data.assistant.trim());
          } else {
            upsertAssistantProgress("Completed.");
          }

          if (typeof data.previewUrl === "string") setPreviewUrl(data.previewUrl);
          if (Array.isArray(data.files)) setGeneratedFiles(data.files.slice(0, 200));
        }

        setIsThinking(false);
        abortRef.current = null;
        return;
      }

      // Unknown content-type
      const fallback = await res.text().catch(() => "");
      const out = fallback?.trim() || "Completed.";
      upsertAssistantProgress(out);
      setIsThinking(false);
      abortRef.current = null;
    } catch (e: any) {
      const aborted = e?.name === "AbortError";
      const err = aborted ? "Cancelled." : `Build request errored: ${String(e?.message || e)}`;
      setLastError(err);
      upsertAssistantProgress(err);
      setIsThinking(false);
      abortRef.current = null;
    }
  }

  const deviceShell = useMemo(() => {
    if (device === "mobile") return { width: 390, height: 844 };
    if (device === "tablet") return { width: 820, height: 1060 };
    return null;
  }, [device]);

  return (
    <AuthGate redirectTo="/login" allowCookieSessionFallback={true}>
      <div className="cb-bg text-white" style={{ minHeight: "100vh" }}>
        <BuilderTopBar
          projectName={activeProjectName}
          onProjectRename={(name) => setActiveProjectName(name)}
          onNewProject={newProjectLocal}
          onShareProject={shareProject}
          onExportProject={exportProject}
          view={view}
          onViewChange={setView}
          device={device}
          onDeviceChange={setDevice}
        />

        <div
          className="cb-builder-shell"
          style={{
            gridTemplateColumns: `${leftW}px 10px minmax(0, 1fr)`,
            minHeight: "calc(100vh - var(--cb-topbar-h, 60px))",
          }}
        >
          <aside className="cb-sidebar cb-sidebar--full">
            <BuilderSidebar
              isThinking={isThinking}
              messages={messages}
              promptDraft={promptDraft}
              onPromptDraftChange={setPromptDraft}
              onRunBuild={runBuild}
            />
          </aside>

          <div
            role="separator"
            aria-orientation="vertical"
            aria-label="Resize panels"
            tabIndex={0}
            onMouseDown={startDrag}
            onKeyDown={(e) => {
              if (e.key === "ArrowLeft") resizeBy(-12);
              if (e.key === "ArrowRight") resizeBy(12);
            }}
            className="cb-resizer hidden lg:block"
            title="Drag to resize • Arrow keys work too"
          >
            <div className="cb-resizer__pill" />
          </div>

          <main className="cb-main">
            <div className="cb-stage">
              <div className="cb-stage-head">
                <div className="cb-stage-title">{view === "preview" ? "Preview" : "Code"}</div>
                <div className="cb-stage-sub">
                  {isThinking ? "Running build…" : view === "preview" ? "Live preview mount" : "Generated files"}
                </div>

                <div className="cb-stage-head__actions" style={{ marginLeft: "auto", display: "flex", gap: 8 }}>
                  {isThinking ? (
                    <button className="cb-btn cb-btn--sm cb-btn--ghost" onClick={cancelRun} type="button">
                      Cancel
                    </button>
                  ) : null}
                </div>
              </div>

              <div className="cb-stage-body cb-stage-body--builder" style={{ minHeight: 0 }}>
                <div className="cb-device-frame cb-device-frame--fill" style={{ minHeight: 0 }}>
                  <div className="cb-device-canvas" style={{ minHeight: 0 }}>
                    {view === "preview" ? (
                      deviceShell ? (
                        <div
                          style={{
                            width: deviceShell.width,
                            height: deviceShell.height,
                            maxWidth: "100%",
                            maxHeight: "100%",
                            borderRadius: 18,
                            border: "1px solid rgba(255,255,255,0.07)",
                            background: "rgba(0,0,0,0.18)",
                            overflow: "hidden",
                            display: "grid",
                            placeItems: "center",
                          }}
                        >
                          {previewUrl ? (
                            <iframe
                              title="Preview"
                              src={previewUrl}
                              style={{ width: "100%", height: "100%", border: 0 }}
                              sandbox="allow-scripts allow-same-origin allow-forms allow-modals"
                            />
                          ) : (
                            <div className="cb-preview-empty">
                              <div className="cb-preview-icon">⬚</div>
                              <div className="cb-preview-h1">Preview ready</div>
                              <div className="cb-preview-p">
                                Run a build to populate the preview. If your backend returns <code>previewUrl</code>, it
                                renders here.
                              </div>
                              {lastError ? (
                                <div className="cb-preview-p" style={{ color: "var(--cb-bad, #ff4d4d)" }}>
                                  {lastError}
                                </div>
                              ) : null}
                            </div>
                          )}
                        </div>
                      ) : (
                        <div className="cb-preview-fill" style={{ minHeight: 0 }}>
                          {previewUrl ? (
                            <iframe
                              title="Preview"
                              src={previewUrl}
                              style={{ width: "100%", height: "100%", border: 0 }}
                              sandbox="allow-scripts allow-same-origin allow-forms allow-modals"
                            />
                          ) : (
                            <div className="cb-preview-empty">
                              <div className="cb-preview-icon">⬚</div>
                              <div className="cb-preview-h1">Preview mount</div>
                              <div className="cb-preview-p">
                                This area is reserved for runtime preview. If your backend returns{" "}
                                <code>previewUrl</code>, it shows here.
                              </div>
                              {lastError ? (
                                <div className="cb-preview-p" style={{ color: "var(--cb-bad, #ff4d4d)" }}>
                                  {lastError}
                                </div>
                              ) : null}
                            </div>
                          )}
                        </div>
                      )
                    ) : (
                      <div className="cb-code-empty" style={{ width: "100%", height: "100%", overflow: "auto" }}>
                        <div className="cb-preview-icon">{"</>"}</div>
                        <div className="cb-preview-h1">Generated files</div>
                        <div className="cb-preview-p">
                          If your backend returns a <code>files</code> array, it will be shown below.
                        </div>

                        {generatedFiles.length ? (
                          <div style={{ width: "100%", marginTop: 14, display: "grid", gap: 12 }}>
                            {generatedFiles.map((f) => (
                              <div
                                key={f.path}
                                style={{
                                  border: "1px solid rgba(255,255,255,0.08)",
                                  borderRadius: 14,
                                  overflow: "hidden",
                                  background: "rgba(0,0,0,0.18)",
                                }}
                              >
                                <div
                                  style={{
                                    padding: "10px 12px",
                                    fontSize: 12,
                                    opacity: 0.9,
                                    borderBottom: "1px solid rgba(255,255,255,0.06)",
                                    display: "flex",
                                    justifyContent: "space-between",
                                    gap: 12,
                                  }}
                                >
                                  <span
                                    style={{
                                      fontFamily:
                                        "ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace",
                                    }}
                                  >
                                    {f.path}
                                  </span>
                                  <button
                                    className="cb-btn cb-btn--sm cb-btn--ghost"
                                    type="button"
                                    onClick={async () => {
                                      try {
                                        await navigator.clipboard.writeText(f.content);
                                      } catch {
                                        window.prompt("Copy file contents:", f.content);
                                      }
                                    }}
                                    title="Copy file"
                                  >
                                    Copy
                                  </button>
                                </div>
                                <pre
                                  className="cb-code-pre"
                                  style={{
                                    margin: 0,
                                    padding: 12,
                                    whiteSpace: "pre-wrap",
                                    wordBreak: "break-word",
                                    fontSize: 12,
                                  }}
                                >
                                  {f.content}
                                </pre>
                              </div>
                            ))}
                          </div>
                        ) : (
                          <pre className="cb-code-pre">
{`No files yet.

Have your backend return JSON like:
{
  "assistant": "…",
  "previewUrl": "https://… (optional)",
  "files": [{ "path": "app/page.tsx", "content": "..." }]
}`}
                          </pre>
                        )}

                        {lastError ? (
                          <div style={{ marginTop: 12, color: "var(--cb-bad, #ff4d4d)" }}>{lastError}</div>
                        ) : null}
                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="cb-stage-foot">
                <span className="cb-kbd">Project</span>
                <span className="cb-stage-foot__proj">
                  {activeProjectName} • {projectId.slice(0, 8)}
                </span>

                <div className="cb-stage-foot__actions">
                  <button
                    className="cb-btn cb-btn--sm cb-btn--ghost"
                    onClick={() => resizeBy(-20)}
                    title="Narrow sidebar"
                    type="button"
                  >
                    ◀
                  </button>
                  <button
                    className="cb-btn cb-btn--sm cb-btn--ghost"
                    onClick={() => resizeBy(20)}
                    title="Widen sidebar"
                    type="button"
                  >
                    ▶
                  </button>
                </div>
              </div>
            </div>
          </main>
        </div>
      </div>
    </AuthGate>
  );
}
